    15→///
    16→/// Among a few other things, the configuration primarily controls the way we
    17→/// show search results to users at a very high level.
    18→#[derive(Clone, Debug)]
    19→struct Config {
    20→    preprocessor: Option<std::path::PathBuf>,
    21→    preprocessor_globs: ignore::overrides::Override,
    22→    search_zip: bool,
    23→    binary_implicit: grep::searcher::BinaryDetection,
    24→    binary_explicit: grep::searcher::BinaryDetection,
    25→}
    26→
    27→impl Default for Config {
    28→    fn default() -> Config {
