    31→            preprocessor_globs: ignore::overrides::Override::empty(),
    32→            search_zip: false,
    33→            binary_implicit: grep::searcher::BinaryDetection::none(),
    34→            binary_explicit: grep::searcher::BinaryDetection::none(),
    35→        }
