    52→impl SearchWorkerBuilder {
    53→    /// Create a new builder for configuring and constructing a search worker.
    54→    pub(crate) fn new() -> SearchWorkerBuilder {
    55→        let mut command_builder = grep::cli::CommandReaderBuilder::new();
    56→        command_builder.async_stderr(true);
    57→
    58→        SearchWorkerBuilder { config: Config::default(), command_builder }
