   146→    if let Some(ref stats) = stats {
   147→        let wtr = searcher.printer().get_mut();
   148→        let _ = print_stats(mode, stats, started_at, wtr);
   149→    }
   150→    Ok(matched)
   151→}
   152→
   153→/// The top-level entry point for multi-threaded search.
   154→///
   155→/// The parallelism is itself achieved by the recursive directory traversal.
   156→/// All we need to do is feed it a worker for performing a search on each file.
   157→///
   158→/// Requesting a sorted output from ripgrep (such as with `--sort path`) will
   159→/// automatically disable parallelism and hence sorting is not handled here.
   160→fn search_parallel(args: &HiArgs, mode: SearchMode) -> anyhow::Result<bool> {
   161→    use std::sync::atomic::{AtomicBool, Ordering};
   162→
   163→    let started_at = std::time::Instant::now();
   164→    let haystack_builder = args.haystack_builder();
   165→    let bufwtr = args.buffer_writer();
   166→    let stats = args.stats().map(std::sync::Mutex::new);
   167→    let matched = AtomicBool::new(false);
   168→    let searched = AtomicBool::new(false);
   169→
   170→    let mut searcher = args.search_worker(
   171→        args.matcher()?,
   172→        args.searcher()?,
   173→        args.printer(mode, bufwtr.buffer()),
   174→    )?;
   175→    args.walk_builder()?.build_parallel().run(|| {
   176→        let bufwtr = &bufwtr;
   177→        let stats = &stats;
   178→        let matched = &matched;
   179→        let searched = &searched;
   180→        let haystack_builder = &haystack_builder;
   181→        let mut searcher = searcher.clone();
   182→
   183→        Box::new(move |result| {
   184→            let haystack = match haystack_builder.build_from_result(result) {
   185→                Some(haystack) => haystack,
   186→                None => return WalkState::Continue,
   187→            };
   188→            searched.store(true, Ordering::SeqCst);
   189→            searcher.printer().get_mut().clear();
   190→            let search_result = match searcher.search(&haystack) {
   191→                Ok(search_result) => search_result,
   192→                Err(err) => {
   193→                    err_message!("{}: {}", haystack.path().display(), err);
   194→                    return WalkState::Continue;
   195→                }
   196→            };
   197→            if search_result.has_match() {
   198→                matched.store(true, Ordering::SeqCst);
   199→            }
   200→            if let Some(ref locked_stats) = *stats {
   201→                let mut stats = locked_stats.lock().unwrap();
   202→                *stats += search_result.stats().unwrap();
   203→            }
   204→            if let Err(err) = bufwtr.print(searcher.printer().get_mut()) {
   205→                // A broken pipe means graceful termination.
   206→                if err.kind() == std::io::ErrorKind::BrokenPipe {
   207→                    return WalkState::Quit;
   208→                }
   209→                // Otherwise, we continue on our merry way.
   210→                err_message!("{}: {}", haystack.path().display(), err);
   211→            }
   212→            if matched.load(Ordering::SeqCst) && args.quit_after_match() {
   213→                WalkState::Quit
   214→            } else {
   215→                WalkState::Continue
   216→            }
   217→        })
   218→    });
   219→    if args.has_implicit_path() && !searched.load(Ordering::SeqCst) {
   220→        eprint_nothing_searched();
   221→    }
   222→    if let Some(ref locked_stats) = stats {
   223→        let stats = locked_stats.lock().unwrap();
   224→        let mut wtr = searcher.printer().get_mut();
   225→        let _ = print_stats(mode, &stats, started_at, &mut wtr);
   226→        let _ = bufwtr.print(&mut wtr);
   227→    }
   228→    Ok(matched.load(Ordering::SeqCst))
   229→}
   230→
   231→/// The top-level entry point for file listing without searching.
   232→///
   233→/// This recursively steps through the file list (current directory by default)
   234→/// and prints each path sequentially using a single thread.
   235→fn files(args: &HiArgs) -> anyhow::Result<bool> {
   236→    let haystack_builder = args.haystack_builder();
   237→    let unsorted = args
   238→        .walk_builder()?
   239→        .build()
   240→        .filter_map(|result| haystack_builder.build_from_result(result));
   241→    let haystacks = args.sort(unsorted);
   242→
   243→    let mut matched = false;
   244→    let mut path_printer = args.path_printer_builder().build(args.stdout());
   245→    for haystack in haystacks {
   246→        matched = true;
   247→        if args.quit_after_match() {
   248→            break;
   249→        }
   250→        if let Err(err) = path_printer.write(haystack.path()) {
   251→            // A broken pipe means graceful termination.
   252→            if err.kind() == std::io::ErrorKind::BrokenPipe {
   253→                break;
   254→            }
   255→            // Otherwise, we have some other error that's preventing us from
   256→            // writing to stdout, so we should bubble it up.
   257→            return Err(err.into());
   258→        }
   259→    }
   260→    Ok(matched)
   261→}
   262→
   263→/// The top-level entry point for multi-threaded file listing without
   264→/// searching.
   265→///
   266→/// This recursively steps through the file list (current directory by default)
   267→/// and prints each path sequentially using multiple threads.
   268→///
   269→/// Requesting a sorted output from ripgrep (such as with `--sort path`) will
   270→/// automatically disable parallelism and hence sorting is not handled here.
   271→fn files_parallel(args: &HiArgs) -> anyhow::Result<bool> {
   272→    use std::{
   273→        sync::{
   274→            atomic::{AtomicBool, Ordering},
   275→            mpsc,
   276→        },
   277→        thread,
   278→    };
   279→
   280→    let haystack_builder = args.haystack_builder();
   281→    let mut path_printer = args.path_printer_builder().build(args.stdout());
   282→    let matched = AtomicBool::new(false);
   283→    let (tx, rx) = mpsc::channel::<crate::haystack::Haystack>();
   284→
   285→    // We spawn a single printing thread to make sure we don't tear writes.
   286→    // We use a channel here under the presumption that it's probably faster
   287→    // than using a mutex in the worker threads below, but this has never been
   288→    // seriously litigated.
   289→    let print_thread = thread::spawn(move || -> std::io::Result<()> {
   290→        for haystack in rx.iter() {
   291→            path_printer.write(haystack.path())?;
   292→        }
   293→        Ok(())
   294→    });
   295→    args.walk_builder()?.build_parallel().run(|| {
   296→        let haystack_builder = &haystack_builder;
   297→        let matched = &matched;
   298→        let tx = tx.clone();
   299→
   300→        Box::new(move |result| {
   301→            let haystack = match haystack_builder.build_from_result(result) {
   302→                Some(haystack) => haystack,
   303→                None => return WalkState::Continue,
   304→            };
   305→            matched.store(true, Ordering::SeqCst);
   306→            if args.quit_after_match() {
   307→                WalkState::Quit
   308→            } else {
   309→                match tx.send(haystack) {
   310→                    Ok(_) => WalkState::Continue,
   311→                    Err(_) => WalkState::Quit,
   312→                }
   313→            }
   314→        })
   315→    });
   316→    drop(tx);
   317→    if let Err(err) = print_thread.join().unwrap() {
   318→        // A broken pipe means graceful termination, so fall through.
   319→        // Otherwise, something bad happened while writing to stdout, so bubble
   320→        // it up.
   321→        if err.kind() != std::io::ErrorKind::BrokenPipe {
   322→            return Err(err.into());
   323→        }
   324→    }
   325→    Ok(matched.load(Ordering::SeqCst))
   326→}
   327→
   328→/// The top-level entry point for `--type-list`.
   329→fn types(args: &HiArgs) -> anyhow::Result<ExitCode> {
   330→    let mut count = 0;
   331→    let mut stdout = args.stdout();
   332→    for def in args.types().definitions() {
   333→        count += 1;
   334→        stdout.write_all(def.name().as_bytes())?;
   335→        stdout.write_all(b": ")?;
   336→
   337→        let mut first = true;
   338→        for glob in def.globs() {
   339→            if !first {
   340→                stdout.write_all(b", ")?;
   341→            }
   342→            stdout.write_all(glob.as_bytes())?;
   343→            first = false;
   344→        }
   345→        stdout.write_all(b"\n")?;
   346→    }
   347→    Ok(ExitCode::from(if count == 0 { 1 } else { 0 }))
   348→}
   349→
   350→/// Implements ripgrep's "generate" modes.
   351→///
   352→/// These modes correspond to generating some kind of ancillary data related
   353→/// to ripgrep. At present, this includes ripgrep's man page (in roff format)
   354→/// and supported shell completions.
   355→fn generate(mode: crate::flags::GenerateMode) -> anyhow::Result<ExitCode> {
   356→    use crate::flags::GenerateMode;
   357→
   358→    let output = match mode {
   359→        GenerateMode::Man => flags::generate_man_page(),
   360→        GenerateMode::CompleteBash => flags::generate_complete_bash(),
   361→        GenerateMode::CompleteZsh => flags::generate_complete_zsh(),
   362→        GenerateMode::CompleteFish => flags::generate_complete_fish(),
   363→        GenerateMode::CompletePowerShell => {
   364→            flags::generate_complete_powershell()
   365→        }
   366→    };
   367→    writeln!(std::io::stdout(), "{}", output.trim_end())?;
   368→    Ok(ExitCode::from(0))
   369→}
   370→
   371→/// Implements ripgrep's "special" modes.
   372→///
   373→/// A special mode is one that generally short-circuits most (not all) of
   374→/// ripgrep's initialization logic and skips right to this routine. The
   375→/// special modes essentially consist of printing help and version output. The
   376→/// idea behind the short circuiting is to ensure there is as little as possible
   377→/// (within reason) that would prevent ripgrep from emitting help output.
   378→///
   379→/// For example, part of the initialization logic that is skipped (among
   380→/// other things) is accessing the current working directory. If that fails,
   381→/// ripgrep emits an error. We don't want to emit an error if it fails and
   382→/// the user requested version or help information.
   383→fn special(mode: crate::flags::SpecialMode) -> anyhow::Result<ExitCode> {
   384→    use crate::flags::SpecialMode;
   385→
   386→    let mut exit = ExitCode::from(0);
   387→    let output = match mode {
   388→        SpecialMode::HelpShort => flags::generate_help_short(),
   389→        SpecialMode::HelpLong => flags::generate_help_long(),
   390→        SpecialMode::VersionShort => flags::generate_version_short(),
   391→        SpecialMode::VersionLong => flags::generate_version_long(),
   392→        // --pcre2-version is a little special because it emits an error
   393→        // exit code if this build of ripgrep doesn't support PCRE2.
   394→        SpecialMode::VersionPCRE2 => {
   395→            let (output, available) = flags::generate_version_pcre2();
   396→            if !available {
   397→                exit = ExitCode::from(1);
   398→            }
   399→            output
   400→        }
   401→    };
   402→    writeln!(std::io::stdout(), "{}", output.trim_end())?;
   403→    Ok(exit)
   404→}
   405→
   406→/// Prints a heuristic error messages when nothing is searched.
   407→///
   408→/// This can happen if an applicable ignore file has one or more rules that
   409→/// are too broad and cause ripgrep to ignore everything.
   410→///
   411→/// We only show this error message when the user does *not* provide an
   412→/// explicit path to search. This is because the message can otherwise be
   413→/// noisy, e.g., when it is intended that there is nothing to search.
   414→fn eprint_nothing_searched() {
   415→    err_message!(
   416→        "No files were searched, which means ripgrep probably \
   417→         applied a filter you didn't expect.\n\
   418→         Running with --debug will show why files are being skipped."
   419→    );
   420→}
   421→
   422→/// Prints the statistics given to the writer given.
   423→///
   424→/// The search mode given determines whether the stats should be printed in
   425→/// a plain text format or in a JSON format.
   426→///
   427→/// The `started` time should be the time at which ripgrep started working.
   428→///
   429→/// If an error occurs while writing, then writing stops and the error is
   430→/// returned. Note that callers should probably ignore this errror, since
   431→/// whether stats fail to print or not generally shouldn't cause ripgrep to
   432→/// enter into an "error" state. And usually the only way for this to fail is
   433→/// if writing to stdout itself fails.
   434→fn print_stats<W: Write>(
   435→    mode: SearchMode,
   436→    stats: &grep::printer::Stats,
   437→    started: std::time::Instant,
   438→    mut wtr: W,
   439→) -> std::io::Result<()> {
   440→    let elapsed = std::time::Instant::now().duration_since(started);
   441→    if matches!(mode, SearchMode::JSON) {
   442→        // We specifically match the format laid out by the JSON printer in
   443→        // the grep-printer crate. We simply "extend" it with the 'summary'
   444→        // message type.
   445→        serde_json::to_writer(
   446→            &mut wtr,
   447→            &serde_json::json!({
   448→                "type": "summary",
   449→                "data": {
   450→                    "stats": stats,
   451→                    "elapsed_total": {
   452→                        "secs": elapsed.as_secs(),
   453→                        "nanos": elapsed.subsec_nanos(),
   454→                        "human": format!("{:0.6}s", elapsed.as_secs_f64()),
   455→                    },
   456→                }
   457→            }),
   458→        )?;
   459→        write!(wtr, "\n")
   460→    } else {
   461→        write!(
   462→            wtr,
   463→            "
   464→{matches} matches
   465→{lines} matched lines
   466→{searches_with_match} files contained matches
   467→{searches} files searched
   468→{bytes_printed} bytes printed
   469→{bytes_searched} bytes searched
   470→{search_time:0.6} seconds spent searching
   471→{process_time:0.6} seconds total
   472→",
   473→            matches = stats.matches(),
   474→            lines = stats.matched_lines(),
   475→            searches_with_match = stats.searches_with_match(),
   476→            searches = stats.searches(),
   477→            bytes_printed = stats.bytes_printed(),
   478→            bytes_searched = stats.bytes_searched(),
   479→            search_time = stats.elapsed().as_secs_f64(),
   480→            process_time = elapsed.as_secs_f64(),
   481→        )
   482→    }
   483→}
